      /* ========================================================================
   v6 · INFOGRAPHIC MODE
   Blog-ready infographic with: background-photo upload, split title with
   accent-coloured second line, half-width rows (leaves photo visible),
   auto-picked per-row icon tiles from a 16-entry library, and extensive
   customisation (row style, icon style, row count, footer alignment, etc.).
   ======================================================================== */

      function switchMode(mode) {
        S.mode = mode;
        const isCard = mode === "card";
        document.getElementById("cardModeFields").style.display = isCard
          ? ""
          : "none";
        document.getElementById("igModeFields").style.display = isCard
          ? "none"
          : "";
        const bCard = document.getElementById("modeBtnCard");
        const bIG = document.getElementById("modeBtnIG");
        if (bCard && bIG) {
          bCard.style.background = isCard ? "var(--accent)" : "transparent";
          bCard.style.color = isCard ? "white" : "var(--text-dim)";
          bIG.style.background = isCard ? "transparent" : "var(--accent)";
          bIG.style.color = isCard ? "var(--text-dim)" : "white";
        }
        const sub = document.querySelector(".logo-sub");
        if (sub)
          sub.textContent = isCard
            ? "v6.1 · SKILL CARDS"
            : "v6.1 · BLOG INFOGRAPHICS";
        // Update empty-state message for current mode
        const emptyTitle = document.getElementById("emptyStateTitle");
        const emptyHint  = document.getElementById("emptyStateHint");
        const emptyIcon  = document.getElementById("emptyStateIcon");
        if (emptyTitle) emptyTitle.textContent = isCard ? "Configure and generate" : "Design your infographic";
        if (emptyHint)  emptyHint.textContent  = isCard ? "Fill the sidebar → Generate SVG" : "Set title + rows → press G or Generate";
        if (emptyIcon)  emptyIcon.textContent  = isCard ? "◈" : "⬚";
        generate();
      }

      /* ---------- v6 upload / colour helpers ---------- */

      function handleIGBgUpload(ev) {
        const file = ev.target.files && ev.target.files[0];
        if (!file) return;
        if (file.size > 12 * 1024 * 1024) {
          showToast("⚠ Image too large (>12 MB)");
          return;
        }
        // Update filename label
        const nameEl = document.getElementById("igBgFileName");
        if (nameEl) nameEl.textContent = file.name.length > 28 ? file.name.slice(0, 26) + "…" : file.name;
        const reader = new FileReader();
        reader.onload = (e) => {
          S.igBgImage = e.target.result;
          const prev = document.getElementById("igBgPreview");
          if (prev) {
            prev.style.display = "block";
            prev.style.backgroundImage = `url("${e.target.result}")`;
          }
          showToast("✓ Photo loaded");
          generate();
        };
        reader.onerror = () => showToast("⚠ Could not read file");
        reader.readAsDataURL(file);
      }

      function clearIGBg() {
        S.igBgImage = "";
        const prev = document.getElementById("igBgPreview");
        if (prev) { prev.style.display = "none"; prev.style.backgroundImage = ""; }
        const nameEl = document.getElementById("igBgFileName");
        if (nameEl) nameEl.textContent = "Choose image…";
        // Reset file input fully so the same file can be re-selected (browser onchange bug fix)
        const fInput = document.getElementById("igBgFile");
        if (fInput) {
          fInput.value = "";
          fInput.type = "text";
          fInput.type = "file";
        }
        showToast("✓ Photo cleared");
        generate();
      }

      function syncIGAccent() {
        const t = document.getElementById("igAccentColorT").value.trim();
        if (/^#[0-9A-Fa-f]{6}$/.test(t)) {
          document.getElementById("igAccentColor").value = t;
          S.igAccentColor = t;
          generate();
        }
      }

