      function loadIGPreset(key) {
        const p = IG_PRESETS[key];
        if (!p) return;
        document.getElementById("igTitlePlain").value = p.titlePlain;
        document.getElementById("igTitleAccent").value = p.titleAccent;
        document.getElementById("igRows").value = p.rows;
        document.getElementById("igFooter").value = p.footer;
        // let the palette auto-map from the preset's themed skill name (card mode's palette still drives the bg gradient)
        const nameEl = document.getElementById("skillName");
        if (nameEl) {
          nameEl.value = p.skillName;
        }
        applySkillMapIfMatch({ forceSector: false, allowFallback: true });
        generate();
        showToast("✓ Loaded " + key + " preset");
      }

      function parseIGRows(raw, limit) {
        // Names only — any "| 95" style suffix is stripped so old v5 data still works.
        const lines = String(raw || "")
          .split("\n")
          .map((l) => l.trim())
          .filter(Boolean)
          .map((l) => {
            return l.split("|")[0].trim();
          })
          .filter(Boolean);
        const max =
          typeof limit === "number" && limit > 0
            ? Math.min(limit, lines.length)
            : Math.min(12, lines.length);
        return lines.slice(0, max).map((name) => ({ name }));
      }

