      const IG_FALLBACK_PAIRS = [
        { bg: "#6366F1", fg: "#FFFFFF" },
        { bg: "#06B6D4", fg: "#FFFFFF" },
        { bg: "#84CC16", fg: "#0A0F1A" },
        { bg: "#F59E0B", fg: "#FFFFFF" },
        { bg: "#EC4899", fg: "#FFFFFF" },
      ];

      function autoPickRowIcon(name, rowIdx) {
        const n = String(name || "").toLowerCase();
        for (const ic of IG_ICON_LIB) {
          for (const kw of ic.kw) {
            if (n.includes(kw)) return ic;
          }
        }
        // fallback: rotate accent colour and draw the first 2 letters of the skill name
        const pick = IG_FALLBACK_PAIRS[rowIdx % IG_FALLBACK_PAIRS.length];
        return {
          id: "default",
          bg: pick.bg,
          fg: pick.fg,
          glyph: (s, fg, nm) => {
            const letters =
              String(nm || "??")
                .replace(/[^a-zA-Z]/g, "")
                .slice(0, 2)
                .toUpperCase() || "--";
            return `<text x="${s / 2}" y="${s * 0.72}" text-anchor="middle" font-family="'DM Mono',ui-monospace,monospace" font-weight="900" font-size="${s * 0.46}" fill="${fg}">${letters}</text>`;
          },
        };
      }

      function makeInfographic(settings, px) {
        const dims = getIGDims();
        const W = dims.w,
          H = dims.h;
        px = px || "ig";
        const c1 = settings.c1,
          c2 = settings.c2,
          c3 = settings.c3;
        const accent = settings.igAccentColor || "#C7E858";
        const hasPhoto = !!settings.igBgImage;
        const isHalf = (settings.igLayout || "half") === "half";
        const rowStyle = settings.igRowStyle || "pill";
        const iconStyle = settings.igIconStyle || "solid";
        // Per-line font sizes (igTitlePlainSize / igTitleAccentSize, numeric 22–78)
        // Fall back to shared igTitleScale for old presets (sm/md/lg or numeric)
        const _legacyScale = (() => {
          const r = settings.igTitleScale;
          if (typeof r === "number" || /^\d+$/.test(String(r))) return parseFloat(r) / 1000;
          return { sm: 0.038, md: 0.046, lg: 0.054 }[r] || 0.046;
        })();
        const titleScaleFactor = _legacyScale; // kept for maxChars calc
        const plainFSRaw  = settings.igTitlePlainSize  || settings.igTitleScale || 46;
        const accentFSRaw = settings.igTitleAccentSize || settings.igTitleScale || 46;
        const plainScaleFactor  = /^\d+$/.test(String(plainFSRaw))  ? parseFloat(plainFSRaw)  / 1000 : _legacyScale;
        const accentScaleFactor = /^\d+$/.test(String(accentFSRaw)) ? parseFloat(accentFSRaw) / 1000 : _legacyScale;
        const plainFontWeight  = settings.igTitlePlainWeight  || "700";
        const accentFontWeight = settings.igTitleAccentWeight || "800";
        const limit = parseInt(settings.igRowLimit, 10) || 10;
        const rows = parseIGRows(settings.igRows, limit);
        const nRows = rows.length || 1;

        // ---------- layout zones ----------
        const pad = Math.round(W * 0.045);
        const rowsRight = isHalf ? Math.round(W * 0.6) : W - pad;
        const heroTop = Math.round(H * 0.05);
        const heroH = Math.round(H * 0.24);
        const footerBandH = Math.round(H * 0.05);
        const rowsTop = heroTop + heroH + Math.round(H * 0.018);
        const rowsBottom = H - footerBandH - Math.round(H * 0.018);
        const rowsAreaH = Math.max(rowsBottom - rowsTop, 0);
        const rowGapPct =
          { pill: 0.08, card: 0.05, bar: 0.18 }[rowStyle] || 0.08;
        const rowH = rowsAreaH / nRows;
        const rowInner = rowH * (1 - rowGapPct * 2);

        // ---------- typography scale ----------
        const plainFS  = Math.max(24, Math.round(W * plainScaleFactor));
        const accentFS = Math.max(24, Math.round(W * accentScaleFactor));
        const titleFS  = Math.max(plainFS, accentFS); // used for layout spacing
        const subFS = Math.max(10, Math.round(W * 0.013));
        const pillFS = Math.max(9, Math.round(W * 0.0105));
        const nameFS = Math.max(11, Math.round(rowH * 0.24));
        const numFS = Math.max(10, Math.round(rowH * 0.22));
        const footerFS = Math.max(10, Math.round(W * 0.012));
        const tileSize = Math.min(
          Math.round(rowH * 0.78),
          Math.round(W * 0.085),
        );

        // ---------- precompute per-row icons (so defs can reference them) ----------
        const rowIcons = rows.map((r, i) => {
          const ovrd = settings.igRowIcons && settings.igRowIcons[i];
          if (ovrd && ovrd !== 'auto') {
            const found = IG_ICON_LIB.find(ic => ic.id === ovrd);
            if (found) return found;
          }
          return autoPickRowIcon(r.name, i);
        });
        let gradDefs = "";
        if (iconStyle === "gradient") {
          rowIcons.forEach((ic, i) => {
            gradDefs += `<linearGradient id="${px}-t${i}" x1="0" y1="0" x2="1" y2="1"><stop offset="0%" stop-color="${ic.bg}"/><stop offset="100%" stop-color="${ic.bg}" stop-opacity="0.45"/></linearGradient>`;
          });
        }

        // ---------- defs ----------
        const bgType = settings.igBgType || "gradient";
        const dimAlpha = ((settings.igBgDim || 0) / 100).toFixed(2);
        const dimRightAlpha = isHalf
          ? (((settings.igBgDim || 0) / 100) * 0.35).toFixed(2)
          : dimAlpha;

        // Build background-specific gradient defs
        let bgGradDef = "";
        if (bgType === "gradient") {
          const gFrom = settings.igBgGradFrom || c1;
          const gTo   = settings.igBgGradTo   || c2;
          const gDir  = settings.igBgGradDir  || "tl-br";
          bgGradDef = buildIGGradAttr(gDir, px + "-bg", gFrom, gTo);
        } else if (bgType === "mesh") {
          const m1 = settings.igBgMesh1 || c1;
          const m2 = settings.igBgMesh2 || "#1A1040";
          const m3 = settings.igBgMesh3 || "#0A2540";
          const m4 = settings.igBgMesh4 || c2;
          bgGradDef = `
    <radialGradient id="${px}-mesh1" cx="0%"   cy="0%"   r="80%" gradientUnits="objectBoundingBox"><stop offset="0%" stop-color="${m1}" stop-opacity="0.95"/><stop offset="100%" stop-color="${m1}" stop-opacity="0"/></radialGradient>
    <radialGradient id="${px}-mesh2" cx="100%" cy="0%"   r="80%" gradientUnits="objectBoundingBox"><stop offset="0%" stop-color="${m2}" stop-opacity="0.90"/><stop offset="100%" stop-color="${m2}" stop-opacity="0"/></radialGradient>
    <radialGradient id="${px}-mesh3" cx="0%"   cy="100%" r="80%" gradientUnits="objectBoundingBox"><stop offset="0%" stop-color="${m3}" stop-opacity="0.90"/><stop offset="100%" stop-color="${m3}" stop-opacity="0"/></radialGradient>
    <radialGradient id="${px}-mesh4" cx="100%" cy="100%" r="80%" gradientUnits="objectBoundingBox"><stop offset="0%" stop-color="${m4}" stop-opacity="0.85"/><stop offset="100%" stop-color="${m4}" stop-opacity="0"/></radialGradient>`;
        } else {
          // solid / image — keep a simple gradient def as fallback
          bgGradDef = gradAttr(settings.gradDir, px + "-bg");
        }

        const defs = `
    ${bgGradDef}
    <linearGradient id="${px}-dim" x1="0" y1="0" x2="1" y2="0">
      <stop offset="0%" stop-color="#000000" stop-opacity="${dimAlpha}"/>
      <stop offset="${isHalf ? "58%" : "100%"}" stop-color="#000000" stop-opacity="${dimRightAlpha}"/>
    </linearGradient>
    ${gradDefs}
  `;

        // ---------- background layer ----------
        let bgLayer;
        if (bgType === "image" && hasPhoto) {
          // Photo background (only render image element when a photo is actually loaded)
          bgLayer = `
      <image href="${settings.igBgImage}" x="0" y="0" width="${W}" height="${H}" preserveAspectRatio="xMidYMid slice"/>
      <rect width="${W}" height="${H}" fill="url(#${px}-dim)"/>
    `;
        } else if (bgType === "solid") {
          const sc = settings.igBgSolidColor || c1;
          bgLayer = `<rect width="${W}" height="${H}" fill="${sc}"/>`;
        } else if (bgType === "mesh") {
          const base = settings.igBgMeshBase || "#080C1A";
          bgLayer = `
      <rect width="${W}" height="${H}" fill="${base}"/>
      <rect width="${W}" height="${H}" fill="url(#${px}-mesh1)"/>
      <rect width="${W}" height="${H}" fill="url(#${px}-mesh2)"/>
      <rect width="${W}" height="${H}" fill="url(#${px}-mesh3)"/>
      <rect width="${W}" height="${H}" fill="url(#${px}-mesh4)"/>
    `;
        } else {
          // gradient (default)
          bgLayer = `<rect width="${W}" height="${H}" fill="url(#${px}-bg)"/>`;
        }

        // Decorative element layer
        let decorationLayer = "";
        if (bgType !== "image" && settings.igShowDecorations) {
          // Dot grid (always shown when decorations enabled)
          const dotSpacing = Math.max(22, Math.round(W * 0.04));
          const dotCols = Math.floor(W / dotSpacing) + 1;
          const dotRows = Math.floor(H / dotSpacing) + 1;
          let dots = "";
          for (let r = 0; r < dotRows; r++)
            for (let col = 0; col < dotCols; col++)
              dots += `<circle cx="${col * dotSpacing}" cy="${r * dotSpacing}" r="1" fill="${c3}" opacity="0.07"/>`;
          decorationLayer += "<g>" + dots + "</g>";

          // Named decoration style
          const decoStyle    = settings.igDecoStyle    || "orbs";
          const decoPosition = settings.igDecoPosition || "tr";
          const decoOpacity  = settings.igDecoOpacity  != null ? settings.igDecoOpacity : 80;
          decorationLayer += buildIGDecoration(decoStyle, decoPosition, decoOpacity, c2, c3, accent, W, H, heroTop, heroH, settings.igDecoSize != null ? settings.igDecoSize : 100);
        }

        // Pattern overlay
        const patternOverlay = settings.igBgPatternEnable
          ? buildIGPattern(settings.igBgPattern || "dots", c3, settings.igBgPatternOpacity || 10, W, H)
          : "";

        // Overlay effect (vignette / top-glow / etc.)
        const igOverlay = buildIGOverlay(settings.igOverlayStyle || "none", accent, W, H);

        // ---------- content alignment ----------
        const contentAlign = settings.igContentAlign || "left";

        // For center mode we use a fixed-width column centred on the canvas.
        // All content (title + rows) stays within this column so equal whitespace
        // appears on both sides.  Title text is centred within the column; row
        // content (icon + text) is left-anchored within the column.
        const centeredColW = contentAlign === "center"
          ? Math.round(W * 0.84)
          : (rowsRight - pad);
        const colStartX = contentAlign === "center"
          ? Math.round((W - centeredColW) / 2)
          : pad;
        const colEndX = colStartX + centeredColW;

        // Title anchor: truly centred within the column
        const tAlign_x = contentAlign === "center" ? Math.round((colStartX + colEndX) / 2)
                       : contentAlign === "right"  ? colEndX
                       : colStartX;
        const tAlign_anchor = contentAlign === "center" ? "middle"
                            : contentAlign === "right"  ? "end"
                            : "start";

        // ---------- title block ----------
        let titleBlock = "";
        let cursorY = heroTop + Math.round(H * 0.018);

        if (settings.igShowBrandPill) {
          const pillW = Math.round(pillFS * 22);
          const pillH = Math.round(pillFS * 2.4);
          const pillX = contentAlign === "center" ? tAlign_x - pillW / 2
                      : contentAlign === "right"  ? tAlign_x - pillW
                      : tAlign_x;
          titleBlock += `
      <rect x="${pillX}" y="${cursorY}" width="${pillW}" height="${pillH}" rx="${pillH / 2}" fill="${accent}" fill-opacity="0.16" stroke="${accent}" stroke-opacity="0.5" stroke-width="1"/>
      <text x="${pillX + pillW / 2}" y="${cursorY + pillH / 2 + pillFS * 0.36}" text-anchor="middle" font-family="'DM Mono',ui-monospace,monospace" font-size="${pillFS}" fill="${accent}" letter-spacing="0.18em" font-weight="700">EDSTELLAR · SKILL REPORT</text>
    `;
          cursorY += pillH + Math.round(titleFS * 0.45);
        } else {
          cursorY += Math.round(titleFS * 0.3);
        }

        // Plain (white) title line(s)
        const maxTitleW = centeredColW;
        const maxChars = Math.max(12, Math.floor(maxTitleW / (titleFS * 0.52)));
        const plainMaxChars  = Math.max(12, Math.floor(maxTitleW / (plainFS  * 0.52)));
        const accentMaxChars = Math.max(12, Math.floor(maxTitleW / (accentFS * 0.52)));
        const plainLines = wrapIGText(settings.igTitlePlain || "", plainMaxChars);
        plainLines.forEach((line) => {
          titleBlock += `<text x="${tAlign_x}" y="${cursorY + plainFS}" text-anchor="${tAlign_anchor}" font-family="Syne,'Trebuchet MS',system-ui,sans-serif" font-weight="${plainFontWeight}" font-size="${plainFS}" fill="#FFFFFF" letter-spacing="-0.01em">${esc(line)}</text>`;
          cursorY += plainFS * 1.05;
        });

        // Accent (highlighted) title line(s)
        const accentText = settings.igTitleAccent || "";
        if (accentText) {
          const accentLines = wrapIGText(accentText, accentMaxChars);
          accentLines.forEach((line) => {
            titleBlock += `<text x="${tAlign_x}" y="${cursorY + accentFS}" text-anchor="${tAlign_anchor}" font-family="Syne,'Trebuchet MS',system-ui,sans-serif" font-weight="${accentFontWeight}" font-size="${accentFS}" fill="${accent}" letter-spacing="-0.01em">${esc(line)}</text>`;
            cursorY += accentFS * 1.08;
          });
        }

        // Subtitle (optional)
        if (settings.igSubtitle) {
          titleBlock += `<text x="${tAlign_x}" y="${cursorY + subFS * 1.4}" text-anchor="${tAlign_anchor}" font-family="'DM Mono',ui-monospace,monospace" font-size="${subFS}" fill="#FFFFFF" fill-opacity="0.6" letter-spacing="0.1em">${esc(String(settings.igSubtitle).toUpperCase())}</text>`;
          cursorY += subFS * 2.1;
          const lineHalfW = Math.round(W * 0.06);
          const lineX1 = contentAlign === "center" ? tAlign_x - lineHalfW
                       : contentAlign === "right"  ? tAlign_x - lineHalfW * 2
                       : tAlign_x;
          const lineX2 = contentAlign === "center" ? tAlign_x + lineHalfW
                       : contentAlign === "right"  ? tAlign_x
                       : tAlign_x + lineHalfW * 2;
          titleBlock += `<line x1="${lineX1}" y1="${cursorY}" x2="${lineX2}" y2="${cursorY}" stroke="${accent}" stroke-width="3" stroke-linecap="round" opacity="0.85"/>`;
        }

        // ---------- rows ----------
        const numColW  = settings.igShowNumbers ? Math.round(W * 0.055) : 0;
        const tileGap  = Math.round(W * 0.018);
        const innerPad = Math.round(W * 0.014);

        // Numbers live outside the pill in the left margin of the column.
        // The pill (rowBg) starts after the number column.
        const rowColStart = colStartX + numColW;   // pill left edge
        const tileX    = rowColStart + innerPad;   // icon left edge (inside pill)
        const nameX    = tileX + tileSize + tileGap;
        const nameMaxW = colEndX - nameX - innerPad;
        // Row text is always left-anchored after the icon — column itself is centred
        const nameTextX  = contentAlign === "right" ? nameX + nameMaxW : nameX;
        const nameAnchor = contentAlign === "right" ? "end" : "start";

        let rowsSvg = "";
        rows.forEach((r, i) => {
          const icon = rowIcons[i];
          const y = rowsTop + i * rowH;
          const rowY = y + (rowH - rowInner) / 2;
          const cy = y + rowH / 2;

          // Row background starts at rowColStart (after numbers), ends at colEndX
          const rowBgX = rowColStart;
          const rowBgW = colEndX - rowColStart;
          let rowBg = "";
          if (rowStyle === "pill") {
            rowBg = `<rect x="${rowBgX}" y="${rowY}" width="${rowBgW}" height="${rowInner}" rx="${Math.round(rowInner * 0.28)}" fill="#0B1220" fill-opacity="0.74" stroke="${accent}" stroke-opacity="0.1" stroke-width="1"/>`;
          } else if (rowStyle === "card") {
            rowBg = `<rect x="${rowBgX}" y="${rowY}" width="${rowBgW}" height="${rowInner}" rx="${Math.round(rowInner * 0.12)}" fill="#0B1220" fill-opacity="0.85" stroke="${accent}" stroke-opacity="0.15" stroke-width="1.5"/>`;
          } else {
            rowBg = `<line x1="${rowBgX}" y1="${rowY + rowInner - 1}" x2="${colEndX}" y2="${rowY + rowInner - 1}" stroke="${accent}" stroke-opacity="0.18" stroke-width="1"/>`;
          }

          // Numbers sit in the left margin of the column, outside the pill
          let numText = "";
          if (settings.igShowNumbers) {
            const numX = rowColStart - Math.round(numColW * 0.15);
            numText = `<text x="${numX}" y="${cy + numFS * 0.36}" text-anchor="end" font-family="'DM Mono',ui-monospace,monospace" font-weight="700" font-size="${numFS * 1.05}" fill="${accent}" opacity="0.9">${String(i + 1).padStart(2, "0")}</text>`;
          }

          // icon tile
          const tileY = cy - tileSize / 2;
          let tileBg;
          if (iconStyle === "gradient") {
            tileBg = `<rect x="${tileX}" y="${tileY}" width="${tileSize}" height="${tileSize}" rx="${Math.round(tileSize * 0.2)}" fill="url(#${px}-t${i})"/>`;
          } else if (iconStyle === "outline") {
            tileBg = `<rect x="${tileX}" y="${tileY}" width="${tileSize}" height="${tileSize}" rx="${Math.round(tileSize * 0.2)}" fill="${icon.bg}" fill-opacity="0.18" stroke="${icon.bg}" stroke-width="1.5"/>`;
          } else {
            tileBg = `<rect x="${tileX}" y="${tileY}" width="${tileSize}" height="${tileSize}" rx="${Math.round(tileSize * 0.2)}" fill="${icon.bg}"/>`;
          }
          const glyphInner = icon.glyph(tileSize, icon.fg, r.name);
          const tile = `${tileBg}<g transform="translate(${tileX},${tileY})">${glyphInner}</g>`;

          // name (auto-wraps to 2 lines if needed)
          const nameMaxChars = Math.max(
            18,
            Math.floor(nameMaxW / (nameFS * 0.52)),
          );
          const nameLines = wrapIGText(r.name, nameMaxChars).slice(0, 2);
          if (
            nameLines.length === 2 &&
            wrapIGText(r.name, nameMaxChars).length > 2
          ) {
            // ellipsize the second line if there's overflow
            nameLines[1] = nameLines[1].replace(/\s+\S+$/, "") + " …";
          }
          const nameBlockH = nameLines.length * nameFS * 1.15;
          const nameStartY = cy - nameBlockH / 2 + nameFS * 0.95;
          let nameSvg = "";
          nameLines.forEach((ln, j) => {
            nameSvg += `<text x="${nameTextX}" y="${nameStartY + j * nameFS * 1.18}" text-anchor="${nameAnchor}" font-family="Syne,'Trebuchet MS',system-ui,sans-serif" font-weight="600" font-size="${nameFS}" fill="#FFFFFF">${esc(ln)}</text>`;
          });

          rowsSvg += rowBg + numText + tile + nameSvg;
        });

        // ---------- footer ----------
        const footerText  = settings.igFooter || "edstellar.com";
        const footerAlign = settings.igFooterAlign || "right";
        const logoVariant = settings.igLogoVariant || "white-wordmark";
        const logoScale   = (settings.igLogoScale || 100) / 100;

        const sepY = H - footerBandH - Math.round(footerBandH * 0.2);
        const availH = H - sepY;

        let footerLogoSVG = "";
        let footerTextSVG = "";

        if (logoVariant !== "none") {
          const logoObj = EDSTELLAR_LOGOS.find(l => l.id === logoVariant);
          if (logoObj) {
            // Aspect ratios measured from actual images
            const AR = logoObj.kind === "icon" ? 1.0 : 4.12;
            const logoH = Math.max(14, Math.round(availH * 0.60 * logoScale));
            const logoW = Math.round(logoH * AR);
            const logoY = Math.round(sepY + (availH - logoH) / 2);
            let logoX;
            if (footerAlign === "left")        logoX = pad;
            else if (footerAlign === "center") logoX = Math.round(W / 2 - logoW / 2);
            else                               logoX = W - pad - logoW;

            footerLogoSVG = `<image href="${logoObj.data}" x="${logoX}" y="${logoY}" width="${logoW}" height="${logoH}" preserveAspectRatio="xMidYMid meet"/>`;

            // Show URL text on the opposite side if set
            if (footerText && footerText !== "edstellar.com" && footerText !== "edstellar") {
              let urlX, urlAnchor;
              if (footerAlign === "right")       { urlX = pad;       urlAnchor = "start"; }
              else if (footerAlign === "left")   { urlX = W - pad;   urlAnchor = "end"; }
              else                               { urlX = W - pad;   urlAnchor = "end"; }
              const urlY = Math.round(sepY + availH * 0.6);
              footerTextSVG = `<text x="${urlX}" y="${urlY}" text-anchor="${urlAnchor}" font-family="'DM Mono',ui-monospace,monospace" font-size="${footerFS * 0.82}" fill="#FFFFFF" fill-opacity="0.5" letter-spacing="0.05em">${esc(footerText)}</text>`;
            }
          }
        } else {
          // Fallback: hand-drawn dot + wordmark text
          const footerY = H - Math.round(footerBandH * 0.4);
          let gX, textAnchor;
          if (footerAlign === "left")        { gX = pad;                                  textAnchor = "start"; }
          else if (footerAlign === "center") { gX = W / 2 - Math.round(footerFS * 4.5);  textAnchor = "middle"; }
          else                               { gX = W - pad - Math.round(footerFS * 9.5); textAnchor = "end"; }
          footerLogoSVG = `<g transform="translate(${gX},${footerY - footerFS * 0.95})">
            <circle cx="${footerFS * 0.55}" cy="${footerFS * 0.35}" r="${footerFS * 0.5}" fill="${accent}"/>
            <text x="${footerFS * 1.6}" y="${footerFS * 0.78}" font-family="Syne,'Trebuchet MS',system-ui,sans-serif" font-weight="800" font-size="${footerFS * 1.3}" fill="#FFFFFF" letter-spacing="-0.02em">edstellar</text>
          </g>`;
          if (footerText && footerText !== "edstellar.com" && footerText !== "edstellar") {
            let ftX, ftAnchor;
            if (footerAlign === "left") { ftX = pad; ftAnchor = "start"; }
            else if (footerAlign === "center") { ftX = W / 2; ftAnchor = "middle"; }
            else { ftX = W - pad; ftAnchor = "end"; }
            footerTextSVG = `<text x="${ftX}" y="${footerY + footerFS * 1.3}" text-anchor="${ftAnchor}" font-family="'DM Mono',ui-monospace,monospace" font-size="${footerFS * 0.85}" fill="#FFFFFF" fill-opacity="0.55" letter-spacing="0.05em">${esc(footerText)}</text>`;
          }
        }

        const footer = `
    <line x1="${pad}" y1="${sepY}" x2="${W - pad}" y2="${sepY}" stroke="#FFFFFF" stroke-opacity="0.1" stroke-width="1"/>
    ${footerLogoSVG}
    ${footerTextSVG}
  `;

        return `<svg viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid meet">
    <defs>${defs}</defs>
    ${bgLayer}
    ${decorationLayer}
    ${patternOverlay}
    ${titleBlock}
    ${rowsSvg}
    ${footer}
    ${igOverlay}
  </svg>`;
      }

      function wrapIGText(text, maxCharsPerLine) {
        const words = String(text || "")
          .split(/\s+/)
          .filter(Boolean);
        const lines = [];
        let cur = "";
        for (const w of words) {
          const next = cur ? cur + " " + w : w;
          if (next.length <= maxCharsPerLine) cur = next;
          else {
            if (cur) lines.push(cur);
            cur = w;
          }
        }
        if (cur) lines.push(cur);
        return lines.length ? lines : [""];
      }

      function getIGDims() {
        const el = document.getElementById("igCanvasSize");
        const v = el ? el.value : S.igSize || "1080x1350";
        const [w, h] = v.split("x").map(Number);
        return { w: w || 1080, h: h || 1350 };
      }

      init();

      // Keyboard shortcuts: G = generate, R = randomize
      document.addEventListener('keydown', function(e) {
        const tag = (e.target.tagName || '').toLowerCase();
        if (tag === 'input' || tag === 'textarea' || tag === 'select') return;
        if (e.metaKey || e.ctrlKey || e.altKey) return;
        if (e.key === 'g' || e.key === 'G') { generate(); showToast('⚡ Generated (G)'); }
        if (e.key === 'r' || e.key === 'R') { randomise(); }
        if (e.key === 'p' || e.key === 'P') { downloadPNG(); showToast('↓ PNG saved (P)'); }
      });
